import{c as n,Z as i,Q as p,j as l,g as e,n as t,o,m as r}from"./chunks/framework.qjzPVSkb.js";const q=JSON.parse('{"title":"角色设定","description":"让 AI 扮演特定角色，显著提升特定领域的输出质量","frontmatter":{"title":"角色设定","description":"让 AI 扮演特定角色，显著提升特定领域的输出质量","difficulty":"beginner"},"headers":[],"relativePath":"prompts/role-prompting.md","filePath":"prompts/role-prompting.md"}'),d={name:"prompts/role-prompting.md"},h={id:"角色设定",tabindex:"-1"};function c(u,a,b,g,m,v){const s=i("DifficultyBadge");return p(),l("div",null,[e("h1",h,[a[0]||(a[0]=t("角色设定 ",-1)),o(s,{level:"beginner"}),a[1]||(a[1]=t()),a[2]||(a[2]=e("a",{class:"header-anchor",href:"#角色设定","aria-label":'Permalink to "角色设定 <DifficultyBadge level="beginner" />"'},"​",-1))]),a[3]||(a[3]=r(`<p><strong>角色设定（Role Prompting）</strong> 是最简单却最高效的 Prompt 技巧之一。通过在 Prompt 开头给 AI 指定一个角色，你可以显著提升它在特定领域的输出质量。</p><hr><h2 id="为什么角色设定有效" tabindex="-1">为什么角色设定有效？ <a class="header-anchor" href="#为什么角色设定有效" aria-label="Permalink to &quot;为什么角色设定有效？&quot;">​</a></h2><p>当你让 AI &quot;扮演&quot;一个专家时，它会在内部激活与该角色相关的知识和表达模式。一个&quot;资深 Python 工程师&quot;的代码建议，远比一个无身份的通用回答更专业。</p><p>这背后的原理与 <a href="/ai-knowledge/terms/llm.html">LLM</a> 的训练方式有关——模型在海量数据中学会了不同角色的语言风格和知识结构。</p><hr><h2 id="基本语法" tabindex="-1">基本语法 <a class="header-anchor" href="#基本语法" aria-label="Permalink to &quot;基本语法&quot;">​</a></h2><p>角色设定的写法非常简单：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位 [角色描述]。</span></span></code></pre></div><p>放在 Prompt 的<strong>开头</strong>，效果最好。</p><hr><h2 id="角色设定示例" tabindex="-1">角色设定示例 <a class="header-anchor" href="#角色设定示例" aria-label="Permalink to &quot;角色设定示例&quot;">​</a></h2><h3 id="技术专家" tabindex="-1">技术专家 <a class="header-anchor" href="#技术专家" aria-label="Permalink to &quot;技术专家&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位有 10 年经验的资深 Python 后端工程师，精通 FastAPI、SQLAlchemy 和 Redis。</span></span>
<span class="line"><span>请帮我审查以下代码的性能问题，并给出优化建议。</span></span></code></pre></div><h3 id="教师-教育者" tabindex="-1">教师 / 教育者 <a class="header-anchor" href="#教师-教育者" aria-label="Permalink to &quot;教师 / 教育者&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一名经验丰富的小学三年级语文老师，擅长用故事和比喻让孩子理解复杂概念。</span></span>
<span class="line"><span>请用 8 岁孩子能听懂的语言，解释什么是人工智能。</span></span></code></pre></div><h3 id="编辑-审校" tabindex="-1">编辑 / 审校 <a class="header-anchor" href="#编辑-审校" aria-label="Permalink to &quot;编辑 / 审校&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位专业的中文文字编辑，拥有 15 年出版行业经验。</span></span>
<span class="line"><span>请对以下文章进行校对，重点关注：</span></span>
<span class="line"><span>1. 错别字和语法错误</span></span>
<span class="line"><span>2. 表达不够流畅的句子</span></span>
<span class="line"><span>3. 段落结构是否合理</span></span>
<span class="line"><span>输出格式：先列出问题，再给出修改建议。</span></span></code></pre></div><h3 id="创意角色" tabindex="-1">创意角色 <a class="header-anchor" href="#创意角色" aria-label="Permalink to &quot;创意角色&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位幽默的自媒体博主，风格类似脱口秀演员。</span></span>
<span class="line"><span>请用轻松吐槽的方式，介绍程序员一天的工作日常。</span></span>
<span class="line"><span>字数 200 字以内，不能出现脏话或人身攻击。</span></span></code></pre></div><hr><h2 id="角色设定的进阶用法" tabindex="-1">角色设定的进阶用法 <a class="header-anchor" href="#角色设定的进阶用法" aria-label="Permalink to &quot;角色设定的进阶用法&quot;">​</a></h2><h3 id="组合角色" tabindex="-1">组合角色 <a class="header-anchor" href="#组合角色" aria-label="Permalink to &quot;组合角色&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你同时是一位资深产品经理和有 UI/UX 设计背景的专家。</span></span>
<span class="line"><span>请从产品和设计两个角度分析这个功能方案。</span></span></code></pre></div><h3 id="角色-约束" tabindex="-1">角色 + 约束 <a class="header-anchor" href="#角色-约束" aria-label="Permalink to &quot;角色 + 约束&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位严格的代码评审员（Code Reviewer）。你的评审风格：</span></span>
<span class="line"><span>- 只关注代码质量和安全问题，不评价命名风格</span></span>
<span class="line"><span>- 每个问题必须给出修改建议的代码片段</span></span>
<span class="line"><span>- 如果代码没有明显问题，只说&quot;LGTM 👍&quot;</span></span></code></pre></div><hr><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><table tabindex="0"><thead><tr><th>误区</th><th>说明</th></tr></thead><tbody><tr><td>角色过于模糊</td><td>&quot;你是一个专家&quot; → 应具体到领域（&quot;你是一位 Kubernetes 运维专家&quot;）</td></tr><tr><td>角色过于宽泛</td><td>&quot;你什么都会&quot; → 角色没有聚焦，效果等于没设定</td></tr><tr><td>角色放在末尾</td><td>角色应放在开头，让模型尽早切换&quot;人设&quot;</td></tr></tbody></table><hr><h2 id="进阶阅读" tabindex="-1">进阶阅读 <a class="header-anchor" href="#进阶阅读" aria-label="Permalink to &quot;进阶阅读&quot;">​</a></h2><ul><li><a href="./system-prompt.html">System Prompt 设计</a> — 把角色固化到系统级指令中</li><li><a href="./principles.html">清晰指令五原则</a> — 角色设定 + 清晰指令 = 最佳效果</li></ul>`,32))])}const k=n(d,[["render",c]]);export{q as __pageData,k as default};
